class Solution {
public:
    int shortestMatchingSubstring(string s, string p) {
        int n = s.size(), m = p.size();
        int first_star = p.find('*'), second_star = p.find('*', first_star + 1);
        int pre_len = first_star, mid_len = second_star - first_star - 1, suff_len = m - second_star - 1;

        int min_len = INT_MAX;
        for (int i = 0; i <= n; ++i) {
            if (i + pre_len > n) break;
            string pre = s.substr(i, pre_len);
            if (pre != p.substr(0, pre_len)) continue;

            int j = i + pre_len;
            while (j <= n && !match(s, p, j, pre_len, mid_len, second_star)) ++j;

            if (j <= n) {
                int match_len = j - i + suff_len;
                if (j + suff_len <= n && s.substr(j, suff_len) == p.substr(second_star + 1, suff_len)) {
                    min_len = min(min_len, match_len);
                }
            }
        }

        return min_len == INT_MAX ? -1 : min_len;
    }

    bool match(const string& s, const string& p, int start, int pre_len, int mid_len, int second_star) {
        int i = start, j = pre_len + 1;
        while (i < s.size() && j <= second_star) {
            if (s[i] == p[j]) {
                ++i;
                ++j;
            } else {
                ++i;
            }
        }
        return j > second_star;
    }
};
